import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes, MouseEventHandler, ReactNode } from 'react';
export interface ExpansionPanelProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
    /** Состояние развёрнут / свёрнут */
    open?: boolean;
    /** Заголовок, текст / пользовательская структура с собственными стилями */
    title: string | ReactNode;
    /** Подзаголовок */
    subTitle?: string | ReactNode;
    /** Описание */
    description?: string | ReactNode;
    /** Событие на открытие */
    onOpen?: MouseEventHandler;
    /** Событие на закрытие */
    onClose?: MouseEventHandler;
    /** Пользовательский класс */
    className?: string;
    /** Название иконки в заголовке */
    iconName?: Icons;
    /** Пользовательский класс для стилизации контейнера заголовка */
    titleClassName?: string;
    /** Пользовательский класс для стилизации контейнера тела  */
    bodyClassName?: string;
    /** Кастомная кнопка вместо стандартной иконки */
    customButton?: ReactNode;
}
